VALUES
  ('social-worker-moex-02861', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '慈濟基金會的國際賑災已經是世界馳名，請問該組織所把握的救援五大原則是那些？請選出最適切答案：', '["及時、直接、重點、尊重、務實", "及時、直接、間接、尊重、務實", "長期、間接、重點、同理、復原", "及時、間接、全面、同理、復原"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02862', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於綜融取向（generalist approach）之社會工作，下列那個論述是錯誤的？', '["1970年代以後，傳統社會工作五大方法（包括個案、團體、社區工作，以及行政與研究）分立受到挑戰", "受到1960年代優勢觀點的影響所發展出來的", "大部分求助的問題很少是單一因素決定問題來源", "有效的介入經常是指大的體系觀點的介入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02863', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一項對任務中心社會個案工作（task-centered casework）之描述是不恰當的？', '["面對困難總要有計畫做點事（do something）", "1960-1970年代由紐約社區服務會社從實務中發展出來", "為短期個案工作處理方式", "由Hollis發展且提出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02864', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '敘事治療（narrative therapy）主要論述基礎為何？請選出最適當的答案：', '["脈絡主義觀點（contextualism）、真實的敘事建構（narrative constructive of reality）、敘事的真實性、 敘事自我的可變性、敘事建構的社會基礎", "脈絡主義觀點（contextualism）、虛擬的敘事建構（narrative constructive of non-reality）、敘事自我的 可變性、敘事建構的社會基礎", "脈絡主義觀點（contextualism）、虛擬的敘事建構（narrative constructive of non-reality）、敘事自我的 客觀性、敘事建構的社會基礎", "脈絡主義觀點（contextualism）、真實的敘事建構（narrative constructive of reality）、敘事自我的客觀 性、敘事建構的社會基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02865', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關生態系統觀點應用於社會工作實務之敘述，何者最正確？', '["視個人或家庭所經歷的問題與困境，是個人的病態所致", "視個人或家庭問題的產生，為某一特定因素", "在介入處遇時，應善用個人或家庭的生活經驗與非正式支持系統，以為介入的切入點", "介入時，其解決之道以單一主要因素為目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02866', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一項不是優勢觀點的基本論述：', '["每個個體、團體、家庭和社區都有優勢", "案主的創傷可能有傷害性，但也可能是生命中成長的機會", "認真看待個體（案主）的期盼（aspiration）", "服務使用者身處的每個環境通常是充滿「病因」與「問題」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02867', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列是有關社會工作的法定義務項目，請問何者是不適用的？', '["告知的義務", "標準的義務", "尊重隱私的義務", "照顧的義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02868', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作常用到危機處遇模式，請問危機處遇的三級工作，由第一到第三級依序為：', '["危機預防、危機事件控制、危機減害", "危機事件控制、危機減害、危機預防", "危機減害、危機事件控制、危機預防", "危機預防、危機減害、危機事件控制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02869', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Lowenberg & Dolgoff（1992）曾經提出倫理原則的順序表，下列那項倫理之優先說明是正確的？', '["自由自主原則優（先）於保護生命原則", "一個人免於傷害的基本保障，優於保密原則", "其他專業倫理要求，優於社工員對社工專業倫理之要求", "甲之次級需要，優於乙之基本生活需要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02870', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一項不是社會工作之主要功能？', '["受創復原的功能（restoration）", "提供資源的功能（provision of resources）", "預防的功能（prevention）", "社會再建構的功能（social re-construction）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02871', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '主張「從改善人們和外在環境的適當調合（person-environment fit）」開始，是下列那一種社會工作模式 的說法？', '["優勢模型", "生活模型", "調和模式", "問題解決模型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02872', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關「後現代主義」社會工作觀點的敘述，那一項是錯誤的？', '["後現代社會工作不認為秩序、確定、安全是可實現的", "後現代社會工作強調論述與語言的重要性", "後現代社會工作強調具體行動，即「推論的實踐」（discursive practice ）", "後現代社會工作認為現實與真實是一致的，不是流動的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02873', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會暨心理學派的實施原則中，以下何種觀點錯誤？', '["應以個別化為原則", "以直接滿足案主需要來協助案主解決問題", "重視案主參與問題研判和處置計畫的建構過程", "社會暨心理服務過程中的決定是不斷修正的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02874', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '學者Mcleod & Meyer（1967）整理出十項社會工作在實務運作中衝突的價值，其中一項是「針對貧窮的 人，有人認為需靠社會集體的力量加以協助；但也有人認為每個人都應該刻苦奮鬥，不應仰賴社會救濟， 成為社會的負擔」，這是屬於何種衝突的價值？', '["集體責任對個人責任（collective responsibility VS. individual responsibility）", "安全滿足對刻苦奮鬥（security-satisfaction VS. struggle, suffering and denial）", "個人自由對社會控制（personal liberty VS. social control）", "相互依賴對個人自治（interdependence VS. individual autonomy）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02875', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Turner（2000）提出社會工作實務可以配合理論著重的重點不同，選擇適合的相關理論，以下有關各理論 著重重點的描述，何者錯誤？', '["理論著重個人是學習者（person as a learner）：行為理論（behavioral theory）", "理論著重個人是個別化的（person as individual）：案主中心取向（client-centered approach）", "理論著重個人是溝通者（person as communicator）：充權觀點（empowerment）", "理論著重個人與世界的關係（person in relation to the universe）：系統理論（system theory）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02876', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '我國社會救助法第11條規定，生活扶助的協助內容以下列何者為原則？', '["機構照顧", "居家照顧", "現金給付", "實物給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02877', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依我國社會工作師法，社會工作師及專科社會工作師執業，應接受繼續教育，並於多久提出完成繼續教 育證明文件，以辦理執業執照更新？', '["每四年", "每五年", "每六年", "每七年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02878', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關老人社會工作中常見理論的描述，何者正確？', '["交換理論（exchange theory），該理論指出因為年齡因素，當個人從職場上離開時，相對的也失去了權 力，這是一種社會退縮（social withdrawal）現象", "活動理論（activity theory），該理論指出工作活動是生活中最重要的一環，因此一旦個人離開工作活 動，就需要尋找其他活動以填補工作活動的空缺", "發展理論（developmental theory），強調生命發展週期的影響，尤其是每個週期中個人要如何去因應該 週期的負面影響（negative affection）", "撤退理論（disengagement theory），認為個人面對老化議題時，從心理層面（psychological level）認為 自己不再適宜參與社會，而導致退縮行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02879', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作教育訓練的描述，下列那一項是正確的？', '["1898年全美社工員協會（National Association of Social Workers）設立，是美國第一個社工專業組織", "1898年倫敦成立第一個慈善組織會社，開始提供睦鄰服務", "美國第一個社會工作員專業組織是「美國社會工作員協會（American Association of Social Workers）」，於 1898年成立", "1898年紐約慈善組織會社於哥倫比亞大學開設社工員專業教育訓練課程，是為社會工作專業訓練之始"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02880', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一項不屬於美國NASW所揭櫫的社會工作四大目標？', '["增強人們解決問題、抗衡與發展的能量", "解決人類衝突、促進社會祥和", "連結人與環境體系，以獲得資源、服務與機會", "發展與促進社會政策"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02881', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '早期英國的慈善組織會社（Charity Organization Society, COS）所採取的是以下何種早期社會工作原則？', '["高蘭（Galan）的危機介入原則", "查墨斯（Thomas Chalmers）的睦鄰原則", "佛洛依德（Freud）的心理分析原則", "巴克雷（Barclay）的社會照顧計畫原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02882', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作倫理相關理論中，有一個理論持有以下的假設：「社會之善乃個人之善的總合」，請問是下列 那一種理論觀點？', '["德行論", "效用主義", "馬克思主義", "康德主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02883', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於「依附理論」（attachment theory），下列那一個敘述是錯誤的？', '["照顧者的心智會與嬰兒的心智相通，稱為「心心相遇的交互主觀」（mind-to-mind encounter intersubjectivity）", "兒童要發展出安全的依附關係，需要有敏感而情緒調和的照顧者", "照顧者冷漠、嚴苛，或是拒絕孩子的需求，小孩有可能發展出「逃避依附」（avoidant attachment）", "「依附理論」（attachment theory）認為依附妨礙獨立，所以主張最好不要依附"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02884', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作理論中的「問題解決模型」，下列描述何者是錯誤的？', '["強調一起工作的人（person）、待處理的問題（problem），工作地點（place）以及工作過程（process）", "認為解決問題的關鍵，主要是在問題解決的機率（probability）", "代表人物是波爾曼（Helen Perlman）", "受到自我心理學（ego psychology）的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02885', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關精神分析理論（Psychoanalysis）內容的描述，何者錯誤？', '["強調性心理發展階段（stage of psychosexual development）", "提出人格的組成包含本我、自我及超我三大部分", "主張人的心靈應包含意識、前意識與潛意識等三部分", "重視人與人的互動經驗，透過互動方能進入他人意識的世界"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
